using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace ApiMcpServer;

/// <summary>
/// MCP tools that wrap a REST API. Uses constructor injection for HttpClient and ILogger.
/// The SDK creates a new instance per tool call, resolving DI services automatically.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("List all users from the API. Returns JSON array of user objects.")]
    public async Task<string> ListUsers(CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Listing all users");
        var users = await httpClient.GetFromJsonAsync<JsonElement>(
            "/users", cancellationToken);
        return JsonSerializer.Serialize(users, JsonOptions);
    }

    [McpServerTool, Description("Get a single user by their numeric ID.")]
    public async Task<string> GetUser(
        [Description("The numeric user ID to look up")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching user {UserId}", userId);
        var response = await httpClient.GetAsync($"/users/{userId}", cancellationToken);

        if (!response.IsSuccessStatusCode)
            return $"Error: user {userId} not found (HTTP {(int)response.StatusCode})";

        var user = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(user, JsonOptions);
    }

    [McpServerTool, Description("Create a new user with the given name and email address.")]
    public async Task<string> CreateUser(
        [Description("Full name of the new user")] string name,
        [Description("Email address of the new user")] string email,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating user {Name}", name);
        var payload = new { name, email };
        var response = await httpClient.PostAsJsonAsync("/users", payload, cancellationToken);

        var body = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(body, JsonOptions);
    }
}

